  // Signed pixel offset from sprite center (32-bit to match localparam width)
  logic signed [31:0] dx, dy;
  assign dx = $signed({22'b0, vx}) - $signed({22'b0, cx});
  assign dy = $signed({22'b0, vy}) - $signed({22'b0, cy});

  logic in_bounds;
  assign in_bounds = (dx >= -HALF_W) && (dx < W - HALF_W) &&
                     (dy >= -HALF_H) && (dy < H - HALF_H);

  logic [5:0] row_idx;
  logic [6:0] col_idx;
  assign row_idx = 6'(dy + HALF_H);
  assign col_idx = 7'(dx + HALF_W);

  // override the alpha channel: any colored pixel is made active
  always_comb begin
    logic [3:0] color;
    color = in_bounds ? SPRITE_ROM[row_idx][col_idx] : 4'h8;
    color[3] = |color[2:0];
    sprite_output.color = color;
  end

